1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
22	
23	function isHighlyEnchanted(item: Item): boolean {
24	  return item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD;
25	}
26	
27	function surchargeRate(item: Item): number {
28	  return (item.cursed ? CURSE_SURCHARGE_RATE : 0)
29	    + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
30	}
31	
32	function itemUnmodifiedBasePremium(item: Item): number {
33	  return BASE_PREMIUMS[item.type];
34	}
35	
36	function itemPerItemSurcharge(item: Item): number {
37	  return BASE_PREMIUMS[item.type] * surchargeRate(item);
38	}
39	
40	function sumUnmodifiedBasePremiums(items: Item[]): number {
41	  return items.reduce((sum, item) => sum + itemUnmodifiedBasePremium(item), 0);
42	}
43	
44	function groupByType(items: Item[]): Record<string, Item[]> {
45	  const groups: Record<string, Item[]> = {};
46	  for (const item of items) {
47	    if (!groups[item.type]) groups[item.type] = [];
48	    groups[item.type].push(item);
49	  }
50	  return groups;
51	}
52	
53	function policyBaseForGroup(groupItems: Item[]): number {
54	  return groupItems.length === BLOCK_SIZE
55	    ? BLOCK_OF_THREE_PREMIUM
56	    : sumUnmodifiedBasePremiums(groupItems);
57	}
58	
59	function calculatePolicyBasePremium(items: Item[]): number {
60	  const groups = groupByType(items);
61	  return Object.values(groups).reduce((total, group) => total + policyBaseForGroup(group), 0);
62	}
63	
64	function calculatePerItemSurcharges(items: Item[]): number {
65	  return items.reduce((sum, item) => sum + itemPerItemSurcharge(item), 0);
66	}
67	
68	function loyaltyDiscount(basePremium: number, years: number): number {
69	  return years >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
70	}
71	
72	function followUpDiscount(basePremium: number, priorContract: boolean): number {
73	  return priorContract ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
74	}
75	
76	export function quote({ items, years, priorContract }: { items: Item[]; years: number; priorContract: boolean }): { premium: number } {
77	  const policyBase = calculatePolicyBasePremium(items);
78	  const perItemSurcharges = calculatePerItemSurcharges(items);
79	  const totalDiscounts = loyaltyDiscount(policyBase, years) + followUpDiscount(policyBase, priorContract);
80	  const firstInsuranceSurcharges = items.length * FIRST_INSURANCE_SURCHARGE;
81	  return { premium: Math.ceil(policyBase + perItemSurcharges - totalDiscounts + firstInsuranceSurcharges + PROCESSING_FEE) };
82	}
83	
84	export function claim(_input: unknown): unknown {
85	  return undefined;
86	}
